import 'package:flutter/material.dart';
import 'package:flutter/widgets.dart';
import 'package:flutter_app_for_issues/components/navigation/routes.dart';
import 'package:flutter_app_for_issues/pages/steps/numeric_page.dart';

class HostScreen extends StatefulWidget {
  const HostScreen({Key? key}) : super(key: key);

  @override
  _HostScreenState createState() => _HostScreenState();
}

class _HostScreenState extends State<HostScreen> {
  final GlobalKey<NavigatorState> navigatorKey = GlobalKey();

  int pageCounter = 1;

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.red,
      body: SafeArea(
        child: GestureDetector(
          onTap: () {
            if (FocusScope.of(context).enclosingScope != null) {
              FocusScope.of(context).unfocus();
            }
          },
          child: Column(
            children: [
             Container(
                color: Colors.blue,
                width: double.infinity,
                height: 50,
              ),
              Expanded(
                child: Navigator(
                  key: navigatorKey,
                  onGenerateRoute: (settings) {
                    return InstanceRoute(
                      page: NumericPage(
                        numberOfPage: pageCounter,
                      ),
                    );
                  },
                ),
              ),
              Row(
                children: [
                  Expanded(
                    child: TextButton(
                      child: const Text('Back'),
                      onPressed: () {
                        if (navigatorKey.currentState?.canPop() ?? false) {
                          navigatorKey.currentState?.pop();
                          --pageCounter;
                        } else {
                          Navigator.pop(context);
                        }
                      },
                    ),
                  ),
                  Expanded(
